// Ingest & Normalize (manual testing fix)

// Directly get the body from the 'Edit Fields' node.
const editFieldsData = $items("Edit Fields")[0].json;
const body = editFieldsData.body;

if (!body || !body.session_id || !body.message) {
  throw new Error("Could not find body.session_id or body.message in 'Edit Fields' node. Ensure it is wired correctly and the fields are set.");
}

const sessionId = body.session_id;
const message = String(body.message ?? "").trim();

// Get other inputs (for database results)
const otherItems = $input.all();

// Find previous state from any input
let previousState = { ocean:{O:0,C:0,E:0,A:0,N:0}, stable:false, turn_index:0 };
for (const item of otherItems) {
  if (item.json?.state_json) {
    previousState = item.json.state_json;
    break;
  }
}

// Gather conversation history from any inputs
const history = otherItems
  .filter(item => typeof item.json?.role === "string" && typeof item.json?.text === "string")
  .map(item => ({
    role: item.json.role,
    text: String(item.json.text ?? ""),
    created_at: item.json.created_at || null
  }))
  .sort((a,b) => (a.created_at && b.created_at) ? a.created_at.localeCompare(b.created_at) : 0);

// Build the final context for the LLM
const cleanMsg = message.replace(/[\r\n]+/g, " ").slice(0, 1000);
const conversationContext = history.map(t => `${t.role}: ${t.text}`).join("\n") + (cleanMsg ? `\nuser: ${cleanMsg}` : "");

return {
  session_id: sessionId,
  clean_msg: cleanMsg,
  conversation_context: conversationContext,
  ocean_prev: previousState.ocean ?? {O:0,C:0,E:0,A:0,N:0},
  turn_index: (previousState.turn_index ?? 0) + 1,
  history: history
};

// Clean + parse LLM JSON, then EMA smoothing with confidence weighting
const rawMsg = $input.first().json.choices[0].message.content || "";

// Remove markdown fences like ```json ... ```
const cleaned = rawMsg
  .replace(/```json\s*/ig, '')
  .replace(/```/g, '')
  .trim();

// Parse robustly
let detectionResult;
try {
  detectionResult = JSON.parse(cleaned);
} catch (e) {
  const m = cleaned.match(/\{[\s\S]*\}/); // last-resort: grab first JSON object
  if (m) detectionResult = JSON.parse(m[0]);
  else {
    return {
      ocean: { O: 0, C: 0, E: 0, A: 0, N: 0 },
      trait_conf: { O: 0.5, C: 0.5, E: 0.5, A: 0.5, N: 0.5 },
      evidence_quotes: [],
      stable: false,
      stable_count: 0,
      parse_warning: 'Failed to parse LLM JSON; returned defaults',
      raw_preview: rawMsg.slice(0, 200)
    };
  }
}

const rawOcean = detectionResult.ocean || { O: 0, C: 0, E: 0, A: 0, N: 0 };
const traitConf = detectionResult.trait_conf || { O: 0.5, C: 0.5, E: 0.5, A: 0.5, N: 0.5 };
const evidenceQuotes = detectionResult.evidence_quotes || [];
const oceanPrev = $input.all()[0].json.ocean_prev || { O: 0, C: 0, E: 0, A: 0, N: 0 };

const smoothedOcean = {};
let stableCount = 0;
const STABILITY_THRESHOLD = 0.3;
const MAX_ALPHA = 0.4;
const DELTA_CAP = 0.3;

for (const trait of ['O', 'C', 'E', 'A', 'N']) {
  const confidence = Math.max(0.1, Math.min(1.0, traitConf[trait] ?? 0.5));
  const alpha = confidence * MAX_ALPHA;

  const prevValue = oceanPrev[trait] ?? 0;
  const rawValue = Math.max(-1, Math.min(1, rawOcean[trait] ?? 0));
  const uncappedNew = (1 - alpha) * prevValue + alpha * rawValue;

  const delta = uncappedNew - prevValue;
  const cappedDelta = Math.max(-DELTA_CAP, Math.min(DELTA_CAP, delta));
  const newValue = prevValue + cappedDelta;

  smoothedOcean[trait] = Math.max(-1, Math.min(1, newValue));
  if (Math.abs(smoothedOcean[trait]) >= STABILITY_THRESHOLD) stableCount++;
}

const isStable = stableCount >= 3;

return {
  ocean: smoothedOcean,
  trait_conf: traitConf,
  stable: isStable,
  evidence_quotes: evidenceQuotes,
  stable_count: stableCount
};

// Map OCEAN traits to behavioral directives
const ocean = $input.first().json.ocean;
const stable = $input.first().json.stable;

const policyPlan = [];

// Warmth dimension (Agreeableness + Extraversion influence)
const warmthScore = (ocean.A + ocean.E) / 2;
if (warmthScore > 0.2) {
  policyPlan.push('validate user concerns with warmth and empathy');
} else if (warmthScore < -0.2) {
  policyPlan.push('respond professionally and directly without excessive warmth');
} else {
  policyPlan.push('use a balanced, supportive tone');
}

// Directness dimension (Conscientiousness - Neuroticism)
const directnessScore = ocean.C - ocean.N;
if (directnessScore > 0.3) {
  policyPlan.push('use concise, direct language and clear statements');
} else if (directnessScore < -0.3) {
  policyPlan.push('use gentle hedging and softer, more tentative language');
} else {
  policyPlan.push('balance directness with sensitivity');
}

// Questioning style (Openness to experience)
if (ocean.O > 0.3) {
  policyPlan.push('ask one thoughtful, open-ended follow-up question');
} else if (ocean.O < -0.3) {
  policyPlan.push('focus on clear statements rather than exploratory questions');
} else {
  policyPlan.push('include one clarifying question if appropriate');
}

// Assertiveness (Extraversion + Conscientiousness, moderated by Agreeableness)
const assertivenessScore = (ocean.E + ocean.C) / 2;
if (assertivenessScore > 0.4 && ocean.A > 0) {
  policyPlan.push('offer specific, actionable suggestions confidently');
} else if (assertivenessScore < -0.2) {
  policyPlan.push('avoid imperative language and strong directives');
} else {
  policyPlan.push('provide gentle suggestions when appropriate');
}

// Length and pacing (Conscientiousness and Extraversion)
const paceScore = (ocean.C + ocean.E) / 2;
if (paceScore > 0.3) {
  policyPlan.push('keep responses moderately concise and well-structured');
} else if (paceScore < -0.3) {
  policyPlan.push('allow for more detailed, thoughtful responses');
}

// Ensure we don't exceed 4 directives and remove any undefined entries
const finalPolicyPlan = policyPlan.filter(p => p && p.length > 0).slice(0, 4);

return {
  policy_plan: finalPolicyPlan,
  personality_scores: {
    warmth: warmthScore,
    directness: directnessScore,
    assertiveness: assertivenessScore,
    pace: paceScore
  }
};

// FIXED: Verify response for policy adherence and grounding
// Fixed variable naming conflict - renamed conversationContext to avoid duplicate declaration

// Get the draft reply from the LLM response
const draftReply = $input.first()?.json?.choices?.[0]?.message?.content?.trim() || '';

// Get inputs from all previous nodes with safety checks
const allInputs = $input.all();

// Find policy plan and conversation context with fallbacks
const policyData = allInputs.find(input => input.json?.policy_plan) || {};
const policyPlan = policyData.json?.policy_plan || [];

// RENAMED: conversationContext -> contextForVerification to avoid naming conflict
const contextData = allInputs.find(input => input.json?.conversation_context) || {};
const contextForVerification = (contextData.json?.conversation_context || '').toLowerCase();

const reasons = [];
let passesVerification = true;

// Validate that we have required data
if (!draftReply) {
  reasons.push('No draft reply received from LLM');
  passesVerification = false;
  return {
    draft_reply: 'Error: No response generated',
    decision: 'refine',
    reasons: reasons,
    verification_details: {
      question_count: 0,
      response_length: 0,
      novel_claims_detected: false,
      error: 'Missing draft reply'
    }
  };
}

// Check for potential novel claims (basic heuristics)
const novelClaimIndicators = [
  'research shows', 'studies indicate', 'experts say', 'according to',
  'it is known that', 'science shows', 'data suggests', 'statistics show'
];

for (const indicator of novelClaimIndicators) {
  if (draftReply.toLowerCase().includes(indicator)) {
    reasons.push(`Potential novel claim detected: "${indicator}"`);
    passesVerification = false;
  }
}

// Check question count
const questionCount = (draftReply.match(/\?/g) || []).length;
if (questionCount > 2) {
  reasons.push(`Too many questions (${questionCount}), should be ≤2`);
  passesVerification = false;
}

// Check response length (too short or too long)
if (draftReply.length < 20) {
  reasons.push('Response too short, may not be helpful');
  passesVerification = false;
} else if (draftReply.length > 300) {
  reasons.push('Response too long, should be more concise');
  passesVerification = false;
}

// Check for basic policy adherence (simplified)
const lowerReply = draftReply.toLowerCase();

// Check warmth policy (only if policy plan exists)
if (policyPlan.some && policyPlan.some(p => p.includes('warmth'))) {
  const warmthIndicators = ['understand', 'feel', 'sounds', 'appreciate'];
  if (!warmthIndicators.some(indicator => lowerReply.includes(indicator))) {
    reasons.push('Response may lack required warmth and empathy');
    passesVerification = false;
  }
}

// Check directness policy (only if policy plan exists)
if (policyPlan.some && policyPlan.some(p => p.includes('direct language'))) {
  const hedgingWords = ['maybe', 'perhaps', 'might want to consider', 'you could try'];
  if (hedgingWords.some(word => lowerReply.includes(word))) {
    reasons.push('Response uses hedging language but policy requires directness');
    passesVerification = false;
  }
}

// Determine final decision
const decision = passesVerification ? 'accept' : 'refine';

return {
  draft_reply: draftReply,
  decision: decision,
  reasons: reasons,
  verification_details: {
    question_count: questionCount,
    response_length: draftReply.length,
    novel_claims_detected: reasons.filter(r => r.includes('novel')).length > 0,
    conversation_context_available: !!contextForVerification,
    policy_plan_available: Array.isArray(policyPlan) && policyPlan.length > 0
  }
};

// FIXED: Format final API response with UUID generation (no crypto module needed)
const allInputs = $input.all();

// Simple UUID generator function (no external dependencies)
function generateUUID() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    const r = Math.random() * 16 | 0;
    const v = c == 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

// Get the final reply (either refined or original draft)
const choices = $json.choices || [];
const finalReply = choices.length > 0 ? 
  choices[0].message.content.trim() : 
  'I apologize, but I encountered an issue generating a response.';

// Collect data from previous nodes
const ingestData = allInputs.find(input => input.json?.session_id) || {};
const smoothData = allInputs.find(input => input.json?.ocean) || {};
const policyData = allInputs.find(input => input.json?.policy_plan) || {};
const verifyData = allInputs.find(input => input.json?.decision) || {};

// Extract core data with UUID conversion
const originalSessionId = ingestData.json?.session_id || 'default-session';
// Convert to UUID if it's not already in UUID format
const sessionId = originalSessionId.match(/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i) 
  ? originalSessionId 
  : generateUUID();

const turnIndex = ingestData.json?.turn_index || 1;
const cleanMsg = ingestData.json?.clean_msg || '';

// Return FLAT structure with proper UUID
return {
  // Direct fields for database nodes (with proper UUID)
  session_id: sessionId,
  turn_index: turnIndex,
  role: 'assistant',
  text: finalReply,
  reply: finalReply,
  clean_msg: cleanMsg,

  // Additional response data
  ocean_preview: smoothData.json?.ocean || {O: 0, C: 0, E: 0, A: 0, N: 0},
  policy_plan: policyData.json?.policy_plan || [],
  confidence_scores: smoothData.json?.trait_conf || {},
  evidence_quotes: smoothData.json?.evidence_quotes || [],

  // Verification info
  verification: {
    decision: verifyData.json?.decision || 'accept',
    reasons: verifyData.json?.reasons || []
  },

  // Execution metadata
  execution_id: $workflow.id,
  timestamp: new Date().toISOString(),

  // State snapshot for database
  state_snapshot: {
    session_id: sessionId,
    turn_index: turnIndex,
    ocean: smoothData.json?.ocean || {O: 0, C: 0, E: 0, A: 0, N: 0},
    trait_conf: smoothData.json?.trait_conf || {},
    stable: smoothData.json?.stable || false,
    policy_plan: policyData.json?.policy_plan || [],
    last_updated: new Date().toISOString(),
    execution_id: $workflow.id
  }
};

