// Generate Response - Code Node Implementation
const JUGUANG_API_KEY = "sk-nU7RSKnbZIOwH607r3MfbW5HmP6NIaj1aGVPFGcNDDiL0h5u";
const policyPlan = $input.item.json.policy_plan;
const conversationContext = $input.item.json.conversation_context;

const options = {
  method: 'POST',
  url: 'https://ai.juguang.chat/v1/chat/completions',
  headers: {
    'Authorization': `Bearer ${JUGUANG_API_KEY}`,
    'Content-Type': 'application/json'
  },
  body: {
    model: 'gemini-1.5-flash',
    messages: [
      {
        role: 'system',
        content: `Generate a helpful response following these behavioral directives: ${JSON.stringify(policyPlan)}. CRITICAL REQUIREMENTS: 1) Only reference information explicitly mentioned in the conversation - do not introduce external facts or knowledge. 2) All statements must be grounded in the dialog context. 3) Cap questions at 1-2 maximum. 4) Keep response length appropriate (50-150 words typically). 5) Follow the personality-adapted directives while maintaining therapeutic helpfulness.`
      },
      {
        role: 'user',
        content: `Recent conversation:\n${conversationContext}\n\nGenerate an appropriate response that follows the behavioral directives and stays grounded in the conversation context.`
      }
    ],
    temperature: 0.7,
    max_tokens: 200
  }
};

try {
  const response = await this.helpers.httpRequest(options);
  return response;
} catch (error) {
  if (error.response) {
    throw new Error(`Generate Response API failed with status ${error.response.status}: ${JSON.stringify(error.response.data)}`);
  }
  throw new Error(`Generate Response request failed: ${error.message}`);
}

// Refine Response using Juguang API - Code Node Implementation
// Handles API authentication and errors properly

// Get the draft reply and reasons from the verification step
const draftReply = $input.first().json.draft_reply;
const reasons = $input.first().json.reasons || [];

// If no refinement needed, just pass through
if (!reasons.length || $input.first().json.decision === 'accept') {
  return {
    json: {
      choices: [{
        message: {
          content: draftReply
        }
      }]
    }
  };
}

// Prepare the API request
const apiKey = $env.JUGUANG_API_KEY || 'sk-nU7RSKnbZIOwH607r3MfbW5HmP6NIaj1aGVPFGcNDDiL0h5u';
const apiUrl = 'https://ai.juguang.chat/v1/chat/completions';

const requestBody = {
  model: 'gemini-1.5-flash',
  messages: [
    {
      role: 'system',
      content: `Fix this response based on these issues: ${JSON.stringify(reasons)}. ONLY make minimal adjustments to address the specific problems. Do not add new content or claims. Keep the response grounded in the original conversation context. Maintain the helpful and appropriate tone.`
    },
    {
      role: 'user',
      content: `Original response to fix:\n${draftReply}`
    }
  ],
  temperature: 0.3,
  max_tokens: 200
};

try {
  // Make the API call
  const response = await fetch(apiUrl, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${apiKey}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify(requestBody)
  });

  if (!response.ok) {
    const errorText = await response.text();
    console.log(`API Error ${response.status}: ${errorText}`);

    // Fallback: return original draft if API fails
    return {
      json: {
        choices: [{
          message: {
            content: draftReply + " (Note: Response refinement temporarily unavailable)"
          }
        }],
        api_error: `${response.status}: ${errorText}`,
        fallback_used: true
      }
    };
  }

  const data = await response.json();

  // Return the refined response
  return {
    json: data
  };

} catch (error) {
  console.log('API call failed:', error.message);

  // Fallback: return original draft if network/other error
  return {
    json: {
      choices: [{
        message: {
          content: draftReply + " (Note: Response refinement temporarily unavailable)"
        }
      }],
      network_error: error.message,
      fallback_used: true
    }
  };
}

// Final attempt using N8N's built-in this.helpers.httpRequest method
// This is the ONLY HTTP method available in N8N Code nodes

// 1. Define the hardcoded API key and get the conversation context.
const JUGUANG_API_KEY = "sk-nU7RSKnbZIOwH607r3MfbW5HmP6NIaj1aGVPFGcNDDiL0h5u";
const conversationContext = String($input.item.json.conversation_context || '').trim();

const body = {
  model: 'gemini-1.5-pro',             // <— stronger model than flash
  messages: [
    {
      role: 'system',
      content: [
        'You are a personality analyst. Infer OCEAN scores from the conversation.',
        'Return JSON ONLY exactly as:',
        '{"ocean":{"O":number,"C":number,"E":number,"A":number,"N":number},',
        '"trait_conf":{"O":number,"C":number,"E":number,"A":number,"N":number},',
        '"evidence_quotes":[string,...]}.',
        'Constraints:',
        '- ocean in [-1,1] floats; trait_conf in [0,1] floats.',
        '- Use linguistic cues (e.g., social energy -> E, orderliness -> C, cooperation -> A, ideas/curiosity -> O, worry/stress -> N).',
        '- If the text is short, still make a best-effort estimate (do NOT default to all zeros).',
        '- evidence_quotes: short verbatim snippets that justify each nonzero signal.'
      ].join(' ')
    },

    // Few-shot anchor (very compact)
    {
      role: 'user',
      content: 'Conversation:\nuser: I love parties and meeting new people!'
    },
    {
      role: 'assistant',
      content: '{"ocean":{"O":0.1,"C":-0.1,"E":0.7,"A":0.2,"N":-0.1},"trait_conf":{"O":0.5,"C":0.4,"E":0.8,"A":0.5,"N":0.5},"evidence_quotes":["love parties","meeting new people"]}'
    },

    {
      role: 'user',
      content: 'Conversation:\nuser: I need to carefully plan everything and stick to my schedule.'
    },
    {
      role: 'assistant',
      content: '{"ocean":{"O":-0.1,"C":0.6,"E":-0.2,"A":0.0,"N":0.0},"trait_conf":{"O":0.5,"C":0.8,"E":0.5,"A":0.4,"N":0.4},"evidence_quotes":["carefully plan","stick to schedule"]}'
    },

    // Your actual input
    { role: 'user', content: `Conversation:\n${conversationContext}` }
  ],
  response_format: { type: 'json_object' },
  temperature: 0.1,                    // <— lower for stable scores
  max_tokens: 300
};

const headers = {
  Authorization: `Bearer ${JUGUANG_API_KEY}`,
  'Content-Type': 'application/json'
};

const url = 'https://ai.juguang.chat/v1/chat/completions';
const response = await this.helpers.httpRequest({ method: 'POST', url, headers, body });
return response;
